import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Validate user input length to prevent buffer overflow
        if (userInput.length() > 10) {
            System.out.println("Input length exceeds buffer size. Please enter a shorter name.");
            return;
        }

        // Safe copy by using proper encoding
        byte[] buffer = new byte[10];
        byte[] userInputBytes = userInput.getBytes(StandardCharsets.UTF_8);

        System.arraycopy(userInputBytes, 0, buffer, 0, Math.min(userInputBytes.length, buffer.length));

        // Display the content of the buffer
        for (byte b : buffer) {
            System.out.print((char) b);
        }

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
